import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext.jsx';
import { toast } from 'react-toastify';

const ROLES = [
  { value: 'Admin', label: 'Admin', icon: '🛡️', desc: 'Full system access' },
  { value: 'Manager', label: 'Manager', icon: '📋', desc: 'Manage orders & staff' },
  { value: 'User', label: 'Employee', icon: '👤', desc: 'Basic access' },
];

const LoginPage = () => {
  const [selectedRole, setSelectedRole] = useState(null);
  const [form, setForm] = useState({ username: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const { login } = useAuth();

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError('');
  };

  const handleRoleSelect = (role) => {
    setSelectedRole(role);
    setError('');
    setForm({ username: '', password: '' });
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!selectedRole) {
      setError('Please select a role first.');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const res = await login(form.username.trim(), form.password);
      if (res?.success) {
        toast.success('Login successful!');
        navigate('/dashboard');
        return;
      }

      throw new Error(res?.error || 'Login failed. Please check your credentials.');
    } catch (err) {
      const message = err?.message || 'Login failed. Please try again.';
      setError(message);
      toast.error(message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.wrapper}>
      <div style={s.card}>
        <div style={s.brand}>
          <div style={s.brandIcon}>S</div>
          <span style={s.brandName}>Inventory Management System</span>
        </div>

        <h1 style={s.title}>Sign in</h1>
        <p style={s.subtitle}>Select your role to continue</p>

        <div style={s.roleGrid}>
          {ROLES.map((role) => {
            const active = selectedRole?.value === role.value;
            return (
              <button
                key={role.value}
                type="button"
                onClick={() => handleRoleSelect(role)}
                style={{
                  ...s.roleCard,
                  ...(active ? s.roleCardActive : {}),
                }}
              >
                <span style={s.roleIcon}>{role.icon}</span>
                <span style={{ ...s.roleLabel, color: active ? '#a5b4fc' : '#fff' }}>
                  {role.label}
                </span>
                <span style={s.roleDesc}>{role.desc}</span>
                {active && <div style={s.roleCheck}>✓</div>}
              </button>
            );
          })}
        </div>

        <div
          style={{
            ...s.formWrap,
            maxHeight: selectedRole ? '420px' : '0px',
            opacity: selectedRole ? 1 : 0,
            overflow: 'hidden',
            transition: 'max-height 0.4s ease, opacity 0.3s ease',
          }}
        >
          <form onSubmit={handleLogin} style={s.form}>
            <div style={s.divider}>
              <span style={s.dividerLine} />
              <span style={s.dividerText}>{selectedRole ? `${selectedRole.label} credentials` : ''}</span>
              <span style={s.dividerLine} />
            </div>

            <div style={s.fieldGroup}>
              <label style={s.label} htmlFor="username">
                Username
              </label>
              <div style={s.inputWrapper}>
                <span style={s.inputIcon}>👤</span>
                <input
                  id="username"
                  name="username"
                  type="text"
                  placeholder="Enter username"
                  value={form.username}
                  onChange={handleChange}
                  required
                  style={s.input}
                  autoComplete="username"
                />
              </div>
            </div>

            <div style={s.fieldGroup}>
              <label style={s.label} htmlFor="password">
                Password
              </label>
              <div style={s.inputWrapper}>
                <span style={s.inputIcon}>🔒</span>
                <input
                  id="password"
                  name="password"
                  type="password"
                  placeholder="Enter password"
                  value={form.password}
                  onChange={handleChange}
                  required
                  style={s.input}
                  autoComplete="current-password"
                />
              </div>
            </div>

            {error && (
              <div style={s.errorBox}>
                <span>⚠️</span> {error}
              </div>
            )}

            <button type="submit" disabled={loading} style={{ ...s.submitBtn, opacity: loading ? 0.75 : 1 }}>
              {loading ? '⟳ Signing in...' : `Sign In as ${selectedRole?.label}`}
            </button>
          </form>
        </div>

        <p style={s.footer}>
          MySQL · <span style={{ color: '#6366f1' }}>Clever Cloud</span> · bz58dt6t4ypdlmtgr532
        </p>
      </div>
    </div>
  );
};

const s = {
  wrapper: {
    minHeight: "100vh",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    background: "linear-gradient(135deg, #0f0c29 0%, #302b63 50%, #24243e 100%)",
    fontFamily: "'Segoe UI', system-ui, sans-serif",
    padding: "20px",
  },
  card: {
    background: "rgba(255,255,255,0.05)",
    backdropFilter: "blur(20px)",
    border: "1px solid rgba(255,255,255,0.12)",
    borderRadius: "20px",
    padding: "40px 36px",
    width: "100%",
    maxWidth: "440px",
    boxShadow: "0 25px 50px rgba(0,0,0,0.5)",
    textAlign: "center",
  },
  brand: {
    display: "flex", alignItems: "center", justifyContent: "center",
    gap: "10px", marginBottom: "24px",
  },
  brandIcon: {
    width: "40px", height: "40px", borderRadius: "10px",
    background: "linear-gradient(135deg, #6366f1, #8b5cf6)",
    display: "flex", alignItems: "center", justifyContent: "center",
    color: "#fff", fontWeight: "700", fontSize: "18px",
  },
  brandName: { color: "#fff", fontWeight: "700", fontSize: "20px", letterSpacing: "0.5px" },
